// The custom hook
export const useFaviconLoader = (loading: boolean, interval: number = 2) => {
  useEffect(() => {
    let spinInterval: NodeJS.Timer | null = null;
    const favicon = document.querySelector(
      'link[rel="icon"]'
    ) as HTMLLinkElement;

    if (loading) {
      spinInterval = setInterval(() => {
        favicon.href = getNextFaviconImage();
      }, interval);
    } else {
      if (spinInterval) clearInterval(spinInterval);
      favicon.href = getDefaultFavicon(); // Ensure this returns your default favicon
    }

    return () => {
      if (spinInterval) clearInterval(spinInterval);
    };
  }, [loading, interval]);
};
